  ('locality-1fb53453-moex-00245', 'locality-1fb53453', 'locality-1fb53453-moex-111-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '關於行政指導，下列敘述何者正確？', '["行政指導為行政處分之一種類型", "行政指導如遭相對人明確拒絕，行政機關應即停止", "行政指導原則上採取書面要式主義", "行政指導如有違法，並不生國家賠償之問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:34+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "319", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00246', 'locality-1fb53453', 'locality-1fb53453-moex-111-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '關於都市計畫，下列敘述何者正確？', '["對都市計畫之個別變更屬於法規性質", "都市計畫之定期通盤檢討不可能直接限制一定區域內特定人之權益或增加負擔", "人民不得對都市計畫提起行政爭訟", "人民認都市計畫違反損害其權利，無須先經訴願程序，即得提起都市計畫審查訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:34+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "319", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
